"use client";
import { useState, useEffect, useRef, useCallback } from "react";

// ─── Types & Data ───────────────────────────────────────────────
const SESSIONS = [
  { id: "s1", title: "Project deadline reminders", tag: "work", connections: ["s4", "s3"] },
  { id: "s2", title: "Workout routine planning", tag: "health", connections: ["s6"] },
  { id: "s3", title: "Book recommendations list", tag: "personal", connections: ["s1"] },
  { id: "s4", title: "Meeting notes — Q3 review", tag: "work", connections: ["s1", "s5"] },
  { id: "s5", title: "Travel itinerary for Japan", tag: "personal", connections: ["s4", "s6"] },
  { id: "s6", title: "Recipe ideas for the week", tag: "health", connections: ["s2", "s5"] },
  { id: "s7", title: "AI tools research", tag: "tech", connections: ["s3", "s1"] },
  { id: "s8", title: "Morning journal — focus", tag: "personal", connections: ["s2"] },
];

const TAG_COLORS = {
  work: { dot: "#4f8aff", glow: "rgba(79,138,255,0.35)", ring: "rgba(79,138,255,0.15)" },
  health: { dot: "#34d399", glow: "rgba(52,211,153,0.35)", ring: "rgba(52,211,153,0.15)" },
  personal: { dot: "#a78bfa", glow: "rgba(167,139,250,0.35)", ring: "rgba(167,139,250,0.15)" },
  tech: { dot: "#fb923c", glow: "rgba(251,146,60,0.35)", ring: "rgba(251,146,60,0.15)" },
};

const RESPONSES = {
  task: Here are your key tasks this week:\n\n• **Project Alpha deadline** — Friday, June 20\n• **Team sync call** — Wednesday at 3 PM\n• **Review design mockups** — Thursday morning\n• **Send Q3 report** — Friday EOD\n\nTuesday looks open — a good window to tackle Alpha deliverables.,
  yesterday: You were working on the **Q3 performance review presentation** yesterday. You had outlined 4 sections and completed 2.\n\nYou also saved a note: *"Check Sarah's data on user retention — she sent it via email."*\n\nWant me to pull up the full outline?,
  idea: Here are your 5 most recently saved ideas:\n\n1. **Offline-first app concept** — sync when reconnected\n2. **Weekly memo format** — 3 bullets + 1 blocker\n3. **Reading habit tracker** using screen time data\n4. **Team retro template** you sketched Monday\n5. **AI journaling prompt** for end-of-day reflection,
  remind: Reminder set ✓\n\nI'll surface this before your deadline. I also noticed you're typically busy on Thursdays, so I'll flag it Wednesday evening too.\n\nShould I set a mid-point check-in?,
  default: [
    "I've stored that in your persistent memory. I'll surface it automatically when it becomes relevant to future conversations.",
    "Got it — indexed and organized. Based on your past notes, this connects to a few earlier threads. Want me to surface those?",
    "Memory updated. I noticed a pattern here that aligns with something you mentioned last week — should I draw the connection?",
    "Saved. You've been building toward this across several sessions. Want me to compile a full summary of what you've captured so far?",
  ],
};

function getAIResponse(text) {
  const l = text.toLowerCase();
  if (l.includes("task") || l.includes("week") || l.includes("to do")) return RESPONSES.task;
  if (l.includes("yesterday") || l.includes("working on")) return RESPONSES.yesterday;
  if (l.includes("idea") || l.includes("saved") || l.includes("notes")) return RESPONSES.idea;
  if (l.includes("remind") || l.includes("deadline")) return RESPONSES.remind;
  const d = RESPONSES.default;
  return d[Math.floor(Math.random() * d.length)];
}

function generateId() {
  return Math.random().toString(36).slice(2, 10);
}

// ─── Node Graph ──────────────────────────────────────────────────
const NODE_POSITIONS = [
  { x: 310, y: 180 }, // s1
  { x: 150, y: 300 }, // s2
  { x: 480, y: 120 }, // s3
  { x: 200, y: 100 }, // s4
  { x: 430, y: 310 }, // s5
  { x: 270, y: 360 }, // s6
  { x: 500, y: 230 }, // s7
  { x: 100, y: 190 }, // s8
];

function NodeGraph({ sessions, activeId, onSelect }) {
  const svgRef = useRef(null);
  const [hovered, setHovered] = useState(null);
  const [dragging, setDragging] = useState(null);
  const [positions, setPositions] = useState(() =>
    sessions.reduce((acc, s, i) => {
      acc[s.id] = NODE_POSITIONS[i] || { x: 200 + Math.random() * 200, y: 150 + Math.random() * 200 };
      return acc;
    }, {})
  );
  const dragStart = useRef(null);

  const onMouseDown = useCallback((e, id) => {
    e.stopPropagation();
    const svg = svgRef.current;
    const pt = svg.createSVGPoint();
    pt.x = e.clientX; pt.y = e.clientY;
    const sp = pt.matrixTransform(svg.getScreenCTM().inverse());
    dragStart.current = { ox: positions[id].x - sp.x, oy: positions[id].y - sp.y };
    setDragging(id);
  }, [positions]);

  const onMouseMove = useCallback((e) => {
    if (!dragging) return;
    const svg = svgRef.current;
    const pt = svg.createSVGPoint();
    pt.x = e.clientX; pt.y = e.clientY;
    const sp = pt.matrixTransform(svg.getScreenCTM().inverse());
    setPositions(prev => ({
      ...prev,
      [dragging]: {
        x: Math.max(28, Math.min(572, sp.x + dragStart.current.ox)),
        y: Math.max(28, Math.min(372, sp.y + dragStart.current.oy)),
      }
    }));
  }, [dragging]);

  const onMouseUp = useCallback((e, id) => {
    if (dragging === id && !dragStart.current?.moved) {
      onSelect(id);
    }
    setDragging(null);
    dragStart.current = null;
  }, [dragging, onSelect]);

  // Build edge list (deduplicated)
  const edges = [];
  const seen = new Set();
  sessions.forEach(s => {
    (s.connections || []).forEach(tid => {
      const key = [s.id, tid].sort().join("-");
      if (!seen.has(key) && positions[s.id] && positions[tid]) {
        seen.add(key);
        edges.push({ from: s.id, to: tid });
      }
    });
  });

  return (
    <svg
      ref={svgRef}
      viewBox="0 0 600 400"
      style={{ width: "100%", height: "100%", cursor: dragging ? "grabbing" : "default" }}
      onMouseMove={onMouseMove}
      onMouseUp={() => { setDragging(null); dragStart.current = null; }}
    >
      <defs>
        <filter id="glow-blue">
          <feGaussianBlur stdDeviation="4" result="blur" />
          <feComposite in="SourceGraphic" in2="blur" operator="over" />
        </filter>
        <filter id="glow-soft">
          <feGaussianBlur stdDeviation="2.5" result="blur" />
          <feComposite in="SourceGraphic" in2="blur" operator="over" />
        </filter>
        <radialGradient id="bg-grad" cx="50%" cy="50%" r="50%">
          <stop offset="0%" stopColor="#0f1520" />
          <stop offset="100%" stopColor="#07090f" />
        </radialGradient>
      </defs>

      {/* Background */}
      <rect x="0" y="0" width="600" height="400" fill="url(#bg-grad)" />

      {/* Grid dots */}
      {Array.from({ length: 20 }, (_, i) =>
        Array.from({ length: 14 }, (_, j) => (
          <circle
            key={${i}-${j}}
            cx={i * 30 + 15} cy={j * 30 + 15}
            r="0.7"
            fill="rgba(99,130,255,0.08)"
          />
        ))
      )}

      {/* Edges */}
      {edges.map(({ from, to }) => {
        const fp = positions[from], tp = positions[to];
        const isActive = from === activeId || to === activeId;
        const isHovered = from === hovered || to === hovered;
        return (
          <line
            key={${from}-${to}}
            x1={fp.x} y1={fp.y} x2={tp.x} y2={tp.y}
            stroke={isActive ? "rgba(79,138,255,0.55)" : isHovered ? "rgba(99,130,255,0.3)" : "rgba(99,130,255,0.12)"}
            strokeWidth={isActive ? 1.5 : 1}
            style={{ transition: "stroke 0.25s, stroke-width 0.25s" }}
          />
        );
      })}

      {/* Nodes */}
      {sessions.map((s) => {
        const pos = positions[s.id];
        if (!pos) return null;
        const color = TAG_COLORS[s.tag] || TAG_COLORS.work;
        const isActive = s.id === activeId;
        const isHov = s.id === hovered;
        const r = isActive ? 10 : isHov ? 8.5 : 7;

        return (
          <g
            key={s.id}
            style={{ cursor: "grab" }}
            onMouseDown={(e) => onMouseDown(e, s.id)}
            onMouseUp={(e) => onMouseUp(e, s.id)}
            onMouseEnter={() => setHovered(s.id)}
            onMouseLeave={() => setHovered(null)}
          >
            {/* Outer glow ring */}
            {(isActive || isHov) && (
              <circle
                cx={pos.x} cy={pos.y}
                r={r + 10}
                fill={color.ring}
                style={{ transition: "r 0.2s, fill 0.2s" }}
              />
            )}
            {/* Mid ring */}
            <circle
              cx={pos.x} cy={pos.y}
              r={r + 4}
              fill="none"
              stroke={color.dot}
              strokeWidth={isActive ? 1.5 : 0.8}
              strokeOpacity={isActive ? 0.5 : 0.2}
              style={{ transition: "all 0.2s" }}
            />
            {/* Core dot */}
            <circle
              cx={pos.x} cy={pos.y}
              r={r}
              fill={isActive ? color.dot : rgba(${hexToRgb(color.dot)}, 0.75)}
              filter={isActive ? "url(#glow-soft)" : isHov ? "url(#glow-soft)" : undefined}
              style={{ transition: "all 0.2s" }}
            />
            {/* Inner shine */}
            <circle
              cx={pos.x - r * 0.25} cy={pos.y - r * 0.3}
              r={r * 0.3}
              fill="rgba(255,255,255,0.3)"
            />
            {/* Label */}
            <text
              x={pos.x}
              y={pos.y + r + 13}
              textAnchor="middle"
              fontSize={isActive ? "9.5" : "8.5"}
              fontFamily="Inter, sans-serif"
              fontWeight={isActive ? "600" : "400"}
              fill={isActive ? color.dot : isHov ? "rgba(232,237,245,0.9)" : "rgba(232,237,245,0.5)"}
              style={{ transition: "all 0.2s", userSelect: "none", pointerEvents: "none" }}
            >
              {s.title.length > 22 ? s.title.slice(0, 22) + "…" : s.title}
            </text>
          </g>
        );
      })}
    </svg>
  );
}

function hexToRgb(hex) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result
    ? ${parseInt(result[1], 16)}, ${parseInt(result[2], 16)}, ${parseInt(result[3], 16)}
    : "79, 138, 255";
}

// ─── Message Rendering ───────────────────────────────────────────
function renderContent(text) {
  return text.split(/(\*\*.*?\*\*|\*.*?\*)/g).map((part, i) => {
    if (part.startsWith("**") && part.endsWith("**"))
      return <strong key={i} style={{ color: "#e8edf5", fontWeight: 600 }}>{part.slice(2, -2)}</strong>;
    if (part.startsWith("*") && part.endsWith("*"))
      return <em key={i} style={{ color: "#8b97b3" }}>{part.slice(1, -1)}</em>;
    return <span key={i}>{part}</span>;
  });
}

function formatMessage(content) {
  return content.split("\n").map((line, i) => {
    const isBullet = line.trim().startsWith("•") || line.trim().startsWith("-");
    return (
      <span key={i} className={block ${isBullet ? "pl-2" : ""} ${i > 0 ? "mt-1" : ""}}>
        {renderContent(line)}
      </span>
    );
  });
}

// ─── Chat Message ────────────────────────────────────────────────
function Message({ msg }) {
  const isUser = msg.role === "user";
  return (
    <div style={{ display: "flex", gap: 10, justifyContent: isUser ? "flex-end" : "flex-start", maxWidth: 720, margin: "0 auto" }}>
      {!isUser && (
        <div style={{
          width: 30, height: 30, borderRadius: "50%", flexShrink: 0, marginTop: 2,
          background: "linear-gradient(135deg, #4f8aff, #8b5cf6)",
          boxShadow: "0 0 12px rgba(79,138,255,0.35)",
          display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14
        }}>🧠</div>
      )}
      <div style={{
        maxWidth: "72%", padding: "10px 14px", borderRadius: 16, fontSize: 13.5, lineHeight: 1.65,
        ...(isUser
          ? { background: "linear-gradient(135deg, #1e3a6e, #1e4d96)", border: "1px solid rgba(79,138,255,0.28)", borderTopRightRadius: 4, color: "#dce8ff" }
          : { background: "#0c1018", border: "1px solid rgba(99,130,255,0.12)", borderTopLeftRadius: 4, color: "#e8edf5" }
        )
      }}>
        {formatMessage(msg.content)}
      </div>
      {isUser && (
        <div style={{
          width: 30, height: 30, borderRadius: "50%", flexShrink: 0, marginTop: 2,
          background: "linear-gradient(135deg, #1e3a8a, #4f8aff)",
          display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 600, color: "white"
        }}>U</div>
      )}
    </div>
  );
}

// ─── Typing Indicator ─────────────────────────────────────────────
function TypingIndicator() {
  return (
    <div style={{ display: "flex", gap: 10, maxWidth: 720, margin: "0 auto" }}>
      <div style={{ width: 30, height: 30, borderRadius: "50%", background: "linear-gradient(135deg, #4f8aff, #8b5cf6)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14 }}>🧠</div>
      <div style={{ padding: "10px 16px", background: "#0c1018", border: "1px solid rgba(99,130,255,0.12)", borderRadius: 16, borderTopLeftRadius: 4, display: "flex", gap: 5, alignItems: "center" }}>
        {[0, 1, 2].map(i => (
          <div key={i} style={{ width: 6, height: 6, borderRadius: "50%", background: "#4f8aff", animation: bounce 1.2s ${i * 0.2}s ease-in-out infinite }} />
        ))}
      </div>
    </div>
  );
}

// ─── Chat Input ───────────────────────────────────────────────────
function ChatInput({ onSend, disabled }) {
  const [value, setValue] = useState("");
  const ref = useRef(null);

  const handleSend = () => {
    const text = value.trim();
    if (!text || disabled) return;
    onSend(text);
    setValue("");
    if (ref.current) ref.current.style.height = "auto";
  };

  const canSend = value.trim().length > 0 && !disabled;

  return (
    <div style={{ padding: "12px 16px 16px", background: "#07090f" }}>
      <div style={{
        maxWidth: 720, margin: "0 auto",
        background: "#0c1018",
        border: 1px solid ${canSend ? "rgba(99,130,255,0.32)" : "rgba(99,130,255,0.12)"},
        borderRadius: 14,
        boxShadow: canSend ? "0 0 0 3px rgba(79,138,255,0.06), 0 0 20px rgba(79,138,255,0.1)" : "none",
        transition: "border-color 0.2s, box-shadow 0.2s"
      }}>
        <div style={{ display: "flex", alignItems: "flex-end", gap: 8, padding: "10px 14px" }}>
          <textarea
            ref={ref}
            value={value}
            onChange={e => setValue(e.target.value)}
            onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
            onInput={() => { if (ref.current) { ref.current.style.height = "auto"; ref.current.style.height = Math.min(ref.current.scrollHeight, 140) + "px"; } }}
            placeholder="Ask Brain Shadow anything…"
            rows={1}
            disabled={disabled}
            style={{
              flex: 1, resize: "none", outline: "none", background: "transparent",
              color: "#e8edf5", fontSize: 13.5, lineHeight: 1.6, minHeight: 22, maxHeight: 140,
              fontFamily: "Inter, sans-serif", border: "none"
            }}
          />
          <button
            onClick={handleSend}
            disabled={!canSend}
            style={{
              width: 32, height: 32, borderRadius: 10, border: "none", flexShrink: 0,
              background: canSend ? "linear-gradient(135deg, #4f8aff, #8b5cf6)" : "#161e30",
              color: "white", cursor: canSend ? "pointer" : "not-allowed",
              boxShadow: canSend ? "0 0 14px rgba(79,138,255,0.4)" : "none",
              display: "flex", alignItems: "center", justifyContent: "center",
              transition: "all 0.2s", fontSize: 14
            }}
          >➤</button>
        </div>
      </div>
      <p style={{ textAlign: "center", fontSize: 10.5, marginTop: 6, color: "#3d4a66", maxWidth: 720, margin: "6px auto 0" }}>
        Brain Shadow remembers context across all your past conversations.
      </p>
    </div>
  );
}

// ─── Tag Legend ───────────────────────────────────────────────────
function TagLegend() {
  return (
    <div style={{ display: "flex", gap: 10, padding: "8px 12px", borderBottom: "1px solid rgba(99,130,255,0.08)", flexWrap: "wrap" }}>
      {Object.entries(TAG_COLORS).map(([tag, c]) => (
        <div key={tag} style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 10.5, color: "#8b97b3" }}>
